import type { DialogueEntry } from '../../../types';
import { CharacterId } from '../../../characters';

export const scene: DialogueEntry[] = [
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "列車平穩地行駛著，車輪與軌道的撞擊聲形成催眠般的韻律——咔噠、咔噠、咔噠。窗外的城市燈火匯成流動的光河，霓虹招牌、路燈、公寓窗戶的暖光，全都化作模糊的光點。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "車廂內，除了那四個大學生偶爾的笑鬧聲，大部分乘客都在閉目養神或滑著手機。有人戴著耳機，頭輕輕搖晃；有人靠著窗戶，半夢半醒。一切都是如此平凡，如此令人安心。" },
    { characterId: CharacterId.TanakaKenta, character: "健談男大生", dialogue: "欸欸，你們明天要不要一起去打籃球啊？我約了幾個學長⋯⋯" },
    { characterId: CharacterId.SuzukiAsuka, character: "活潑女大生", dialogue: "明天？我想睡到中午耶⋯⋯今天玩得好累喔⋯⋯" },
    { characterId: CharacterId.TakahashiMisaki, character: "多話女大生", dialogue: "對啊對啊，我也超累的，而且明天我還要整理筆記，下週要考試了。教授說這次考試超難的，範圍超大，我都還沒開始準備⋯⋯" },
    { characterId: CharacterId.SatoTakumi, character: "沉穩男大生", dialogue: "明天再說吧。先回家再說。" },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "(內心)總算能安靜一下了⋯⋯這週末也真夠累的。派對、應酬、假笑⋯⋯有時候真想就這樣一個人待著，什麼都不用想。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "就在這時，列車前方出現了隧道的入口——一個巨大的、漆黑的洞口，像一張沉默的巨口。列車毫不遲疑地駛了進去。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "車廂內的燈光自動亮起，發出淡淡的白光。窗外瞬間被純粹的黑暗吞噬。玻璃變成了一面鏡子，映照出乘客們模糊的倒影——疲憊的臉、空洞的眼神。" },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "(內心)啊，是那條隧道了。按照平常的經驗，大概五分鐘就能出去。正好閉目養神一下⋯⋯" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "李杰靠在椅背上，閉上了眼睛。列車運行的單調聲響像催眠曲一樣在耳邊迴響。車輪的「咔噠咔噠」、空調的低沉嗡鳴、還有遠處傳來的金屬摩擦聲。他的呼吸逐漸平緩，意識開始變得模糊。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "一分鐘。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "兩分鐘。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "三分鐘。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "五分鐘過去了。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "李杰下意識地覺得應該要看到光了——隧道盡頭的光芒，城市的燈火，熟悉的夜景。但眼皮之外，世界依舊昏暗。只有車廂的燈光，還有那無止境的黑暗。" },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "(內心)嗯？怎麼還沒出去？⋯⋯也許是今天比較累，感覺時間過得特別慢吧。應該快了⋯⋯" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他沒有睜開眼，只是調整了一下姿勢,繼續閉目養神。又過了五分鐘。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "車廂內恆定的空調聲，以及列車碾過鐵軌的節奏性轟鳴，此刻不再讓人安心。反而像是一種無限循環的詛咒。那聲音太過規律，太過單調，彷彿時間已經停止流動。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "李杰心中的違和感越來越強烈，像是有什麼冰冷的東西爬上了他的脊椎。他終於睜開了眼，拿出手機，想確認一下時間和路線。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "螢幕亮起，冷白色的光芒刺痛了他的眼睛。時間顯示——午夜十二點十五分。他記得列車是十一點五十五分駛離月台的，這意味著，列車已經在隧道裡行駛了整整二十分鐘。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他的目光移向螢幕頂端——「沒有服務」四個字，清晰地顯示在狀態欄裡。信號格全空。" },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "(內心)二十分鐘⋯⋯這絕對不正常。這條隧道我走過無數次，最多五分鐘就能通過。現在卻⋯⋯不只是我⋯⋯" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "與此同時，車廂另一頭的寧靜被徹底打破了。" },
    { characterId: CharacterId.SuzukiAsuka, character: "活潑女大生", dialogue: "欸⋯⋯不是吧？我的手機完全沒訊號！連「圈外」都不是，是「沒有服務」耶！這底下是多深啊？我從來沒見過這種狀況⋯⋯" },
    { characterId: CharacterId.TanakaKenta, character: "健談男大生", dialogue: "我的也是，什麼都傳不出去。LINE、IG、什麼都不行。喂，這隧道也太長了吧？以前有這麼長嗎？我怎麼一點印象都沒有？" },
    { characterId: CharacterId.TakahashiMisaki, character: "多話女大生", dialogue: "對啊對啊，我也覺得超奇怪的，而且你們有沒有覺得⋯⋯好像已經過了很久？我看了一下時間，已經二十分鐘了耶！這條隧道不是應該很快就過去嗎？" },
    { characterId: CharacterId.SatoTakumi, character: "沉穩男大生", dialogue: "二十分鐘了。不對勁。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "膽小眼鏡男見狀，立刻抓住機會表現自己。他站了起來，故作鎮定地推了推眼鏡。" },
    { characterId: CharacterId.SaitoRen, character: "膽小眼鏡男", dialogue: "各位，不用慌張。這是常識。隧道的結構會嚴重影響信號傳播，電磁波無法穿透厚重的岩層和混凝土，所以手機沒訊號是很正常的。" },
    { characterId: CharacterId.SaitoRen, character: "膽小眼鏡男", dialogue: "另外，深夜線路經常會有維護工程，為了避開施工區域而繞道，導致行駛時間延長個二十分鐘，這在鐵路運營中是非常常見的。你們不用大驚小怪。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他的語氣雖然自信，但額頭上已經滲出了細密的汗珠。幾個大學生面面相覷，表情依然充滿疑惑，顯然並沒有被他的說法說服。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "這時，一個低沉而沉穩的聲音響起，打破了膽小眼鏡男試圖營造的「專業氛圍」。" },
    { characterId: CharacterId.YamamotoKoji, character: "慷慨大叔", dialogue: "小兄弟，話不是這麼說。我坐這條中央線三十年了，從我年輕的時候就開始坐。這條隧道我閉著眼都能數出來需要多久——五分鐘，最多六分鐘。" },
    { characterId: CharacterId.YamamotoKoji, character: "慷慨大叔", dialogue: "從來，從來沒有在隧道裡待超過十分鐘的。這情況⋯⋯不對勁。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "這位大叔的話像一顆石子投入水中，激起了層層漣漪。原本還抱有僥倖心理的乘客們，臉上最後一絲輕鬆也消失了。" },
    { characterId: CharacterId.ItoNana, character: "焦慮妻子", dialogue: "老公⋯⋯我有點不安⋯⋯你不是說這條路你很熟嗎？這、這是怎麼回事？我們會不會出事了？" },
    { characterId: CharacterId.ItoMakoto, character: "煩躁丈夫", dialogue: "我怎麼會知道！我又不是司機！妳問我有什麼用！煩死了，一直問一直問！" },
    { characterId: CharacterId.ItoNana, character: "焦慮妻子", dialogue: "你、你幹嘛這樣兇我⋯⋯" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "不遠處，一個小男孩的聲音響起，稚嫩而充滿恐懼。" },
    { characterId: CharacterId.KobayashiShota, character: "天真弟弟", dialogue: "媽媽⋯⋯我怕黑⋯⋯外面都是黑的⋯⋯我們什麼時候才能出去？我想回家⋯⋯" },
    { characterId: CharacterId.KobayashiTomoko, character: "溫柔母親", dialogue: "快了快了，寶寶乖，你看，姐姐都沒怕。別看窗外了，我們看手機裡的卡通好不好？" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她拿出手機，但螢幕上顯示著「無法載入」。" },
    { characterId: CharacterId.KobayashiTomoko, character: "溫柔母親", dialogue: "啊⋯⋯手機也⋯⋯" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她的聲音戛然而止，臉色變得蒼白。孩子察覺到母親的不安，哭聲更大了。那位母親只能把孩子的臉按在自己懷裡，不讓他看到周圍人臉上的恐懼。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "焦慮像會傳染的病毒，迅速在車廂內蔓延。人們開始交頭接耳，竊竊私語變成了公開的抱怨和質疑。有人開始頻繁地看手錶，有人不停刷新手機，有人站起來走動。" },
    { characterId: CharacterId.NakamuraHayato, character: "自私中年男", dialogue: "喂！肯定出事了！是不是該去按那個緊急通話鈕啊！不然我們就在這裡困到天亮嗎？萬一出事怎麼辦！" },
    { characterId: CharacterId.YamamotoKoji, character: "慷慨大叔", dialogue: "你冷靜點！現在列車還在平穩運行，沒有異常震動，說明軌道和系統都正常。亂按緊急鈕萬一導致緊急停車，卡在隧道中間那才叫危險！到時候連逃生通道都找不到！" },
    { characterId: CharacterId.NakamuraHayato, character: "自私中年男", dialogue: "那你說怎麼辦！就這樣等下去嗎！" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "兩人的爭吵讓車廂內的氣氛更加凝重。有人開始小聲抽泣，有人緊緊抱著包包，還有人呆滯地望著窗外那無盡的黑暗。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "一片混亂中，李杰的目光下意識地再次轉向那個安靜的女孩。她像是身處另一個次元。周圍的騷動絲毫沒有影響到她。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她沒有看手機，也沒有望向窗外，更沒有表現出任何恐慌或不安。她只是安靜地坐在那裡，專注於腿上的素描本，手中的鉛筆在紙上流暢地移動。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "李杰瞇起眼睛，試圖看清她在畫什麼。那不是人物，也不是風景，而是一個由複雜螺旋、尖銳稜角、以及扭曲線條構成的奇異圖騰。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "那些線條彷彿有生命一般，相互纏繞、交織，形成一種令人不安的對稱結構。看起來像某種古老的符號，又像是某種不應存在於這個世界的語言。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她的手沒有停下，彷彿那些圖案早已刻在她的腦海深處，只是通過她的手被複製到紙上。" },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "(內心)在這種時候⋯⋯她還在畫畫？而且畫的是⋯⋯那是什麼東西？那些符號⋯⋯為什麼看起來這麼詭異？她好像⋯⋯完全不屬於這裡，彷彿她早就知道會發生什麼⋯⋯" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "就在車廂內的氣氛越來越凝重，爭吵聲、哭泣聲、質疑聲混雜在一起時——列車前方，黑暗的盡頭，終於滲出了一絲光亮。" },
    { characterId: CharacterId.SatoTakumi, character: "沉穩男大生", dialogue: "啊！有光了！你們看！終於要出去了！" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "這一聲喜悅的呼喊像救贖一樣，讓所有人都停止了爭論。所有的目光，不約而同地投向那片越來越大的光芒。有人站了起來，有人湊到窗邊，有人臉上露出劫後餘生般的笑容。" },
    { characterId: CharacterId.SuzukiAsuka, character: "活潑女大生", dialogue: "嚇死我了⋯⋯終於要出去了⋯⋯" },
    { characterId: CharacterId.TanakaKenta, character: "健談男大生", dialogue: "我就說嘛！一定只是繞路而已！" },
    { characterId: CharacterId.TakahashiMisaki, character: "多話女大生", dialogue: "對啊對啊，我就說沒事的，就是繞路嘛，剛剛嚇死我了，我還以為要出事了，還好還好⋯⋯" },
    { characterId: CharacterId.SaitoRen, character: "膽小眼鏡男", dialogue: "看吧，我早就說了，這是常識⋯⋯" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "但是——所有人的表情，很快就從期待變成了困惑。那光芒⋯⋯有些奇怪。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "它不是城市夜晚那種熟悉的、溫暖的橘黃色光輝。不是路燈的白光。不是霓虹燈的繽紛色彩。而是一種⋯⋯冰冷的、深邃的、詭異的藍黑色光暈。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "像一片沒有星辰的夜空，帶著一股萬物死寂的氣息，正沉默地、耐心地等待著他們。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "光芒越來越近，越來越亮。但車廂內，卻越來越安靜。所有人的笑容都凝固了，取而代之的是一種原始的、本能的恐懼。" },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "(內心)⋯⋯那是什麼光？那絕對不是我熟悉的世界。那是⋯⋯什麼？" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "列車繼續前進，毫不遲疑地駛向那片詭異的光芒。車輪的聲音依舊單調，空調的嗡鳴依舊恆定。但此刻，那聲音聽起來不再像催眠曲——而像是送葬的哀歌。" },
];
